<?php
namespace App\Http\Controllers\Survey;
use App\Http\Controllers\Controller;use App\Http\Requests\Survey\StoreSurveyDraftRequest;use App\Models\{SurveyInstrument,SurveyInvitation,SurveyResponse,SurveyResponseItem};use App\Services\Audit\AuditLogger;use Illuminate\Http\Request;
class SurveyController extends Controller { public function googleRedirect(){ return redirect(config('umkm.oauth.google.redirect')); } public function googleCallback(Request $request, AuditLogger $audit){ $request->validate(['google_id'=>'required|string']); $user=$request->user(); $user?->update(['google_id'=>$request->string('google_id'),'google_linked_at'=>now()]); $audit->log('survey.google.link',$request,'users',$user?->id,[],['google_linked'=>true]); return redirect()->route('survey.list'); } public function list(Request $r){ $items=SurveyInstrument::query()->where('status','active')->where(fn($q)=>$q->whereNull('active_from')->orWhere('active_from','<=',now()))->where(fn($q)=>$q->whereNull('active_until')->orWhere('active_until','>=',now()))->get(); return view('pages.survey.list',compact('items')); } public function fill(Request $r, SurveyInstrument $survey, ?string $token=null){ $inv=$token ? SurveyInvitation::query()->where('token',$token)->first() : null; if($token) abort_unless($inv && !$inv->is_used && $inv->expires_at->isFuture(),403); return view('pages.survey.fill',['survey'=>$survey]); } public function saveDraft(StoreSurveyDraftRequest $request, SurveyInstrument $survey, AuditLogger $audit){ $resp=SurveyResponse::query()->firstOrCreate(['survey_instrument_id'=>$survey->id,'user_id'=>$request->user()->id],['status'=>'draft']); abort_if($resp->status==='submitted',422,'Respon final sudah dikunci'); foreach($request->input('answers',[]) as $qid=>$ans){ SurveyResponseItem::query()->updateOrCreate(['survey_response_id'=>$resp->id,'survey_question_id'=>(int)$qid],['answer'=>(string)$ans]); } $audit->log('survey.draft.save',$request,'survey_responses',$resp->id); return back()->with('status','Draft tersimpan'); } public function submitFinal(Request $request, SurveyInstrument $survey, AuditLogger $audit){ $request->validate(['confirm_submit'=>['required','accepted']]); $resp=SurveyResponse::query()->firstOrCreate(['survey_instrument_id'=>$survey->id,'user_id'=>$request->user()->id],['status'=>'draft']); abort_if($resp->status==='submitted',422,'Satu respons per akun'); $resp->update(['status'=>'submitted','submitted_at'=>now()]); SurveyInvitation::query()->where('survey_instrument_id',$survey->id)->where('user_id',$request->user()->id)->update(['is_used'=>true]); $audit->log('survey.final.submit',$request,'survey_responses',$resp->id); return redirect()->route('survey.list')->with('status','Respons final terkirim'); } public function recap(Request $r, AuditLogger $audit){ $audit->log('survey.recap.view',$r,'survey_recap'); $data=SurveyResponse::query()->selectRaw('survey_instrument_id,status,count(*) as total')->groupBy('survey_instrument_id','status')->get(); return view('pages.survey.recap',compact('data')); }}
